using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    #region CalculatePercentage

    [TestMethod]
    [DataRow(5, 10, 50.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultAlwaysInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));

        Assert.AreEqual("total", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, -1));

        Assert.AreEqual("total", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));

        Assert.AreEqual("correct", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));

        Assert.AreEqual("correct", ex.ParamName);
    }

    #endregion

    #region GetGrade — boundary tests

    [TestMethod]
    [DataRow(90.0, "A", DisplayName = "90 is lower bound of A")]
    [DataRow(95.0, "A", DisplayName = "95 is mid A")]
    [DataRow(100.0, "A", DisplayName = "100 is top A")]
    [DataRow(89.99, "B", DisplayName = "89.99 is just below A")]
    [DataRow(80.0, "B", DisplayName = "80 is lower bound of B")]
    [DataRow(79.99, "C", DisplayName = "79.99 is just below B")]
    [DataRow(70.0, "C", DisplayName = "70 is lower bound of C")]
    [DataRow(69.99, "D", DisplayName = "69.99 is just below C")]
    [DataRow(60.0, "D", DisplayName = "60 is lower bound of D")]
    [DataRow(59.99, "F", DisplayName = "59.99 is just below D")]
    [DataRow(0.0, "F", DisplayName = "0 is F")]
    [DataRow(-5.0, "F", DisplayName = "Negative is F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    #endregion

    #region NormalizeScore

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(0.0, 100.0, 0.0)]
    [DataRow(100.0, 100.0, 100.0)]
    [DataRow(25.0, 50.0, 50.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(double rawScore, double maxRaw, double expected)
    {
        var result = _calculator.NormalizeScore(rawScore, maxRaw);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThanOrEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultAlwaysInRange()
    {
        var result = _calculator.NormalizeScore(42.0, 80.0);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));

        Assert.AreEqual("rawScore", ex.ParamName);
    }

    [TestMethod]
    public void NormalizeScore_ZeroMaxRaw_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));

        Assert.AreEqual("maxRaw", ex.ParamName);
    }

    [TestMethod]
    public void NormalizeScore_NegativeMaxRaw_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));

        Assert.AreEqual("maxRaw", ex.ParamName);
    }

    #endregion
}

